param([Parameter(Mandatory=$true)][string]$CsvFile,[string]$OutputJson="",[string]$BatchId="",[string]$Label="")
$ErrorActionPreference='Stop';$CsvFile=[IO.Path]::GetFullPath($CsvFile.Trim('"'));if(-not(Test-Path $CsvFile)){throw 'CSV not found.'};if(-not $BatchId){$BatchId=[IO.Path]::GetFileNameWithoutExtension($CsvFile)};$BatchId=($BatchId.ToLower() -replace '[^a-z0-9-]+','-' -replace '^-|-$','');if(-not $Label){$Label=$BatchId};if(-not $OutputJson){$OutputJson=Join-Path (Split-Path $CsvFile) ($BatchId+'.json')}
$questions=@();foreach($r in (Import-Csv $CsvFile)){$choices=@();foreach($letter in 'A','B','C','D','E'){$v=$r.('choice'+$letter);if($v){$choices+=[ordered]@{label=$letter;text=$v}}};$q=[ordered]@{id=$r.id;course=$r.course;courseId=$r.courseId;assessmentFamily=$r.assessmentFamily;type=$r.type;year=if($r.year){[int]$r.year}else{$null};questionNumber=$r.questionNumber;section=$r.section;calculator=$r.calculator;prompt=$r.prompt;choices=$choices;answer=$r.answer;workedSolution=$r.workedSolution;classification=[ordered]@{primaryUnit=if($r.primaryUnit){[int]$r.primaryUnit}else{$null};primaryTopic=$r.primaryTopic;topicCode=$r.topicCode};pedagogy=[ordered]@{difficulty=if($r.difficulty){[int]$r.difficulty}else{$null};difficultyLabel=$r.difficultyLabel};quality=[ordered]@{productionStatus='ready';needsReview=$true;transcriptionVerified=$false;answerVerified=$false;mediaVerified=$true;reviewReasons=@('Imported from CSV; teacher verification required.')};source=[ordered]@{officialStatus=$r.officialStatus;sourceFile=$r.sourceFile;sourcePage=$r.sourcePage;accessLevel='private-school-approved'}};$questions+=$q}
$out=[ordered]@{schemaVersion='1.0.0';batchId=$BatchId;label=$Label;mergeMode='upsert';createdAt=(Get-Date).ToUniversalTime().ToString('o');questions=$questions};$out|ConvertTo-Json -Depth 100|Set-Content $OutputJson -Encoding UTF8;Write-Host "Created $OutputJson with $($questions.Count) questions." -ForegroundColor Green
